<CascadingValue Value="currentSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-42c06740e3e54dc99461c51295ece5d1/Components/ScreenSizeProvider.razor.js");
            await jsModule.InvokeVoidAsync("initialize", dotNetRef);
        }
    }

    [JSInvokable]
    public void OnViewportWidthChanged(int width)
    {
        var newSize = width switch
        {
            < 768 => ScreenSize.Mobile,
            < 1024 => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

